SELECT w.*,
       o.order_no,
       o.business_type_code,
       o.container_location,
       o.placing_location,
       o.unloading_location,
       o.return_container_location,
       o.load_time
FROM t_waybill w
LEFT JOIN t_order o ON w.order_id = o.order_id
LEFT JOIN t_shipper s ON s.shipper_id = w.shipper_id

    w.driver_id = #{queryForm.driverId}

        AND w.enterprise_id = #{queryForm.enterpriseId}


        AND ( INSTR(w.waybill_number, #{queryForm.keywords})
        OR INSTR(o.order_no, #{queryForm.keywords})
        OR INSTR(w.container_number, #{queryForm.keywords})
        OR INSTR(w.lead_seal_number, #{queryForm.keywords}) )


        AND w.waybill_status IN

            #{status}



        AND w.shipper_id = #{queryForm.shipperId}


        AND w.vehicle_id = #{queryForm.vehicleId}


        and w.waybill_status = #{queryForm.waybillStatus}


        AND w.pay_status = #{queryForm.payStatus}


        AND DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}



    order by w.waybill_id desc

SELECT COUNT(1)
FROM t_waybill
WHERE driver_id = #{driverId}
AND waybill_status != #{excludeStatus}

